<template>
	<view>
		<view :class="sysconfig.goods.h5_cate_cen?'cateBox1':'cateBox'">

			<template v-if="sysconfig.goods.h5_cate_cen == 1">
				<!-- 左侧列表 -->
				<scroll-view class="cate-left" scroll-y="true" :scroll-top="verticalNavTop" scroll-with-animation>
					<view class="cate-left-list" v-for="(item, index) in data" :key="index" @click="tapselect(index)">
						<!-- activeItem为选中状态 -->
						<view class="cate-left-item" :class="{ activeItem: currentTab == index }">
							<label></label><text class="line1">{{ item.name }}</text>
						</view>
					</view>
				</scroll-view>

				<!-- 右侧列表 -->
				<scroll-view class="cate-right" scroll-y="true" @scroll="mainScroll"
					:scroll-into-view="'cate-' + mainCur" scroll-with-animation>
					<!-- 一级 -->
					<view v-for="(item1, index1) in data" :key="index1" :id="'cate-' + index1" class="cate-wrap">
						<!-- 存在二级 -->
						<template v-if="item1.children && item1.children.length">
							<!-- 存在三级  -->
							<template v-if="item1.has3">

								<view class="cate-box"
									v-if="item1.children.length > 1 && (item1.children.length>item1.has_all)">
									<view class="cate-right-title" @click="itemClick(item1)">
										<image :src="$util.img(item1.img)" mode=""></image><text>{{ item1.name }}</text>
									</view>
									<view class="cate-right-list">
										<view v-for="(item2, index2) in item1.children" :key="index2"
											class="cate-right-item" v-if="!item2.has3" @click="itemClick(item2)">
											<image :src="$util.img(item2.img)" mode=""></image>
											<view class="text line1">{{ item2.name }}</view>
										</view>
									</view>
								</view>

								<!-- 二级 -->
								<view class="cate-box" v-for="(item2, index2) in item1.children" :key="index2">
									<!-- 三级 -->
									<template v-if="item2.has3">
										<view class="cate-right-title" @click="itemClick(item2)">
											<image :src="$util.img(item2.img)" mode=""></image>
											<text>{{ item2.name }}</text>
										</view>
										<view class="cate-right-list">
											<view class="cate-right-item" v-for="(item3, index3) in item2.children"
												:key="index3" @click="itemClick(item3)">
												<image :src="$util.img(item3.img)" mode=""></image>
												<view class="text line1">{{item3.name}}</view>
											</view>
										</view>
									</template>
								</view>
							</template>
							<template v-else>
								<!-- 不存在三级级 -->
								<view class="cate-box">
									<view class="cate-right-title" @click="itemClick(item1)">
										<image :src="$util.img(item1.img)" mode=""></image><text>{{ item1.name }}</text>
									</view>
									<view class="cate-right-list">
										<view v-for="(item2, index2) in item1.children" :key="index2"
											class="cate-right-item" @click="itemClick(item2)">
											<image :src="$util.img(item2.img)" mode=""></image>
											<view class="text line1">{{item2.name}}</view>
										</view>
									</view>
								</view>
							</template>
						</template>
						<template v-else>

							<view class="cate-box">
								<view class="cate-right-title" @click="itemClick(item1)">
									<image :src="$util.img(item1.img)" mode=""></image><text>{{ item1.name }}</text>
								</view>
								<view class="cate-right-list">

								</view>
							</view>

							<!-- <view class="cate-right-title" @click="itemClick(item1)">
								<text>{{ item1.name }}</text><u-icon name="arrow-right"></u-icon>
							</view>
							<view class="cate-right-list"></view> -->
						</template>
					</view>
					<view style="height: 50rpx"></view>
				</scroll-view>
			</template>













			<template v-else>

				<!-- 左侧列表 -->
				<scroll-view class="cate-left" scroll-y="true" :scroll-top="verticalNavTop" scroll-with-animation>
					<view class="cate-left-list" v-for="(item,index) in data" :key="index" @click="tapselect(index)">
						<!-- activeItem为选中状态 -->
						<view class="cate-left-item " :class="{activeItem:currentTab==index}">
							<label></label><text class="line1">{{item.name}}</text>
						</view>
					</view>
				</scroll-view>

				<!-- 右侧列表 -->
				<scroll-view class="cate-right" scroll-y="true" @scroll="mainScroll" :scroll-into-view="'cate-'+mainCur"
					scroll-with-animation>
					<!-- 一级 -->
					<view v-for="(item1,index1) in data" :key="index1" :id="'cate-'+index1">
						<!-- 存在二级 -->
						<template v-if="item1.children && item1.children.length">


							<!-- 存在三级级 -->
							<view class="cate-box">

								<view class="cate-right-title">
									<view class="line"></view>
									<text>{{item1.name}}</text>
								</view>
								<view class="cate-right-list">
									<view v-for="(item2,index2) in item1.children" :key="index2" class="cate-right-item"
										@click="itemClick(item2)">
										<image :src="$util.img(item2.img)" mode=""></image>
										<view class="text line1">{{item2.name}}</view>
									</view>
								</view>
							</view>

						</template>
						<template v-else>
							<view class="cate-right-title">
								<view class="line"></view>
								<text>{{item1.name}}</text>
							</view>
							<view class="cate-right-list"></view>
						</template>
					</view>
					<view style="height: 50rpx;"></view>
				</scroll-view>









			</template>
		</view>
	</view>
</template>

<script>
	export default {
		props: {
			data: {
				type: Array,
				default () {
					return [];
				},
			},

			initTabIndex: {
				type: Number,
				default: 0,
			},
		},
		data() {
			return {
				currentTab: 0,
				mainCur: 0,
				verticalNavTop: 0,
				list: [{}],
			};
		},
		watch: {
			initTabIndex: {
				handler(nv) {
					this.currentTab = nv;
					if (this.initTabIndex) {
						this.tapselect(this.initTabIndex);
					}
				},
				immediate: true,
			},
		},
		mounted() {
			this.getHeight();
			//默认选中
			if (this.initTabIndex) {
				this.tapselect(this.initTabIndex);
			}
		},
		methods: {
			itemClick(item) {
				console.log(item);
				this.$emit("click", item);
			},
			//点击左侧按钮
			tapselect(index) {
				this.currentTab = index;
				this.mainCur = index;
				this.verticalNavTop = (index - 1) * 50;
			},
			//右侧滚动
			mainScroll(e) {
				let scrollTop = e.detail.scrollTop + 10;
				for (let i = 0; i < this.list.length; i++) {
					if (scrollTop > this.list[i].top && scrollTop < this.list[i].bottom) {
						this.currentTab = i;
						this.verticalNavTop = (i - 1) * 50;
						return false;
					}
				}
			},
			//获取右侧每项的top和bottom,里面需获取对应dom元素的高度，所以只能在mounted生命周期里调用
			getHeight() {
				var top = 0;
				var bottom = 0;
				var temp = 0;
				for (let i = 0; i < this.data.length; i++) {
					let view = uni
						.createSelectorQuery()
						.in(this)
						.select("#cate-" + i);
					view
						.fields({
								size: true,
							},
							(data) => {
								top = temp;
								bottom = temp + data.height;
								this.list[i] = {
									top: top,
									bottom: bottom,
								};
								temp = bottom;
							}
						)
						.exec();
				}
			},
		},
	};
</script>

<style lang="scss" scoped scoped>
	.cateBox1 {
		position: absolute;
		top: 10rpx;
		bottom: 0;
		background: #fff;
		width: 100%;
		display: flex;



		.cate-left {
			width: 200rpx;
			background: #fff;
			height: 100%;
		}

		.cate-left-item {
			background: #fff;
			height: 50px;
			display: flex;
			align-items: center;
		}

		.cate-left-item.activeItem {
			background: #f4f4f4;
		}

		.cate-left-item label {
			width: 8rpx;
			height: 15px;
			float: left;
			background: #f4f4f4;
		}

		.cate-left-item.activeItem label {
			background: #0bbbef;
		}

		.cate-left-item text {
			width: 196rpx;
			font-size: 28rpx;
			display: block;
			text-align: center;
		}

		/* 右侧*/
		.cate-right {
			flex: 1;
			background-color: #f4f4f4;

			.cate-wrap {
				.cate-box {
					background-color: #fff;
					margin-left: 20rpx;
					margin-right: 20rpx;
					margin-bottom: 20rpx;
					border-radius: 10rpx;
				}
			}
		}

		.cate-right-title {
			text-align: left;
			font-size: 28rpx;
			line-height: 80rpx;
			position: relative;
			padding-left: 20rpx;
			cursor: pointer;
			display: flex;
			align-items: center;
			gap: 8rpx;

			&>text {
				font-weight: bold;
				color: #333;
				font-size: 30rpx;
				margin-right: 10rpx;
			}

			&:active {
				opacity: 0.8;
			}

			image {
				width: 40rpx;
				height: 40rpx;
				border-radius: 20%;
			}
		}

		.cate-right-list {
			height: auto;
			overflow: hidden;
			display: grid;
			grid-template-columns: repeat(3, 3fr);
		}

		.cate-right-item {
			margin-top: 20rpx;
			overflow: hidden;
		}

		.cate-right-item image {
			width: 90rpx;
			height: 90rpx;
			border-radius: 50%;
			display: block;
			margin: 0 auto;
		}

		.cate-right-item .text {
			text-align: center;
			font-size: 24rpx;
			margin: 12rpx;
		}









	}


	.cateBox {
		position: absolute;
		top: 0;
		bottom: 0;
		background: #fff;
		width: 100%;
		display: flex;

		.cate-left {
			width: 200rpx;
			background: #f4f4f4;
			height: 100%;
		}

		.cate-left-item {
			background: #f4f4f4;
			height: 50px;
			display: flex;
			align-items: center;
		}

		.cate-left-item.activeItem {
			background: #fff;
		}

		.cate-left-item label {
			width: 4rpx;
			height: 15px;
			float: left;
			background: #f4f4f4;
		}

		.cate-left-item.activeItem label {
			background: #0bbbef;
		}

		.cate-left-item text {
			width: 196rpx;
			font-size: 28rpx;
			display: block;
			text-align: center;
		}

		/* 右侧*/
		.cate-right {
			flex: 1;
		}

		.cate-right-title {
			text-align: center;
			font-size: 28rpx;
			margin-top: 20rpx;
			line-height: 80rpx;
			position: relative;
		}

		.cate-right-title .line {
			position: absolute;
			height: 2rpx;
			width: 300rpx;
			background: #f0f0f0;
			top: 39rpx;
			left: 50%;
			margin-left: -150rpx;
		}

		.cate-right-title text {
			background: #fff;
			padding: 0 20rpx;
			position: relative;
			color: #999;
		}

		.cate-right-list {
			height: auto;
			overflow: hidden;
			display: grid;
			grid-template-columns: repeat(3, 3fr);
		}

		.cate-right-item {
			margin-top: 20rpx;
			overflow: hidden;
		}

		.cate-right-item image {
			width: 90rpx;
			height: 90rpx;
			border-radius: 50%;
			display: block;
			margin: 0 auto;
		}

		.cate-right-item .text {
			text-align: center;
			font-size: 24rpx;
			margin: 12rpx;
		}



	}
</style>