<template>
	<view class="u-page">
		<my-page-header>
			<view slot="header">
				<view class="search-box acea-row row-between-wrapper">
					<u-search v-model="keyword" :show-action="false" @search="doSearch"></u-search>
				</view>
			</view>
		</my-page-header>
		<!-- data:商品列表数组[{navtitle:标题 shop:展示列表}] @click:商品条目点击事件-->
		<view class="catelist-box">
			<cc-defineCateList :data="categoryList" :initTabIndex="initTabIndex" @click="cateItemClick"
				v-if="categoryList.length"></cc-defineCateList>
		</view>
		<u-tabbar :height="110" active-color='#f06c7a' inactive-color="#606266" :list="tabBarList"></u-tabbar>
	</view>
</template>

<script>
	import {
		mapActions
	} from 'vuex'
	import MyPageHeader from '@/components/my-page-header'
	export default {
		components: {
			'my-page-header': MyPageHeader,
		},
		data() {
			return {
				keyword: '',
				cpid: 0,
				categoryList: [],
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		computed: {
			initTabIndex() {
				if (this.categoryList.length) {
					let idx = this.categoryList.findIndex(item => item.id == this.cpid)
					return idx != -1 ? idx : 0
				} else
					return 0
			},
		},
		onShow() {
			let params = uni.getStorageSync('tab-params')
			if (params.cpid) {
				this.cpid = params.cpid
				uni.setStorageSync('tab-params', '')
				// #ifdef H5
				this.changeURLArg('cpid', this.cpid)
				// #endif
			}
		},
		onLoad(e) {
			// #ifdef H5
			let params = this.$util.getUrlParams()
			this.cpid = params.cpid || ''
			// #endif			
			this.loadData()
		},
		methods: {
			...mapActions(['setGoTop', 'removeGoTop']),
			updateCateNode(nodes, ids = [], newData) {
				nodes.forEach((node) => {
					if (ids.includes(node.id)) {
						Object.assign(node, newData) // 更新节点数据
					}
					if (node.children && node.children.length > 0) {
						this.updateCateNode(node.children, ids, newData) // 递归到子节点
					}
				})
			},
			async loadData() {
				const {
					category_list
				} = await this.$u.api.category()



				category_list.forEach((node) => {
					//处理是否有三级
					node.has3 = false
					//是否全部为三级
					node.has_all = 0
					if (node.children && node.children.length > 0) {

						for (let i = 0; i < node.children.length; i++) {

							if (node.children[i].children && node.children[i].children.length > 0) {
								node.has3 = true
								node.has_all++
								node.children[i].has3 = true

								// return
							} else {
								node.children[i].has3 = false
							}
						}

					}

				})

				this.categoryList = category_list
			},
			cateItemClick(item) {
				this.$Router.push({
					path: '/pages/goods/list',
					query: {
						id: item.id,
						cpid: item.pid,
						title: item.name
					}
				})
			},
			doSearch() {
				this.$Router.push({
					path: '/pages/goods/list',
					query: {
						keyword: this.keyword
					}
				})
			},
			changeURLArg(arg, arg_val, url = null, replace = true) {
				if (url == null) {
					url = location.href
				}
				var new_url = url
				var pattern = arg + '=([^&]*)'
				var replaceText = arg + '=' + arg_val
				if (url.match(pattern)) {
					var tmp = '/(' + arg + '=)([^&]*)/gi'
					new_url = url.replace(eval(tmp), replaceText)
				} else {
					if (url.match('[\?]')) {
						new_url = url + '&' + replaceText
					} else {
						new_url = url + '?' + replaceText
					}
				}

				if (replace) {
					if (window.history && history.pushState) {
						history.replaceState(null, '', new_url)
					}
				} else {
					return new_url
				}
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.cateBox {

			.cate-left-item {
				height: 100rpx;
			}

			.cate-left-item.activeItem {
				label {
					height: 100%;
					background-color: #fe564b;
				}

				text {
					color: #fe564b;
					font-weight: 600;
				}
			}
		}
	}

	.u-page {
		display: flex;
		flex-direction: column;
		height: 100vh;

		.search-box {
			width: 100%;
			background-color: #fff;
			border-bottom: 1px solid #f5f5f5;
			padding: 0 20rpx;
			height: 88rpx;
		}

		.catelist-box {
			flex: 1;
			position: relative;
		}
	}
</style>